// Constants from Edit Fields
const CONSTANTS = $('Edit fields Constants').first().json;

const ATTR_ID_DEFAULT_CARRIER   = CONSTANTS.attributeIdDefaultShippingCarrier;
const ATTR_ID_EXCLUSION_TAGS    = CONSTANTS.attributeIdServiceExclusionTags;
const ATTR_ID_KLEINPAKET_SHARE  = CONSTANTS.attributeIdKleinpaketShare;

// Parse carriers (array or JSON string)
const SHIPPING_CARRIERS = Array.isArray(CONSTANTS.shippingCarriers)
  ? CONSTANTS.shippingCarriers
  : (() => { try { return JSON.parse(CONSTANTS.shippingCarriers || '[]'); } catch { return []; } })();

// Parse selectable values for default carrier (array or JSON string)
const SELECTABLE_DEFAULT_CARRIER = Array.isArray(CONSTANTS.selectableValueDefaultCarrier)
  ? CONSTANTS.selectableValueDefaultCarrier
  : (() => { try { return JSON.parse(CONSTANTS.selectableValueDefaultCarrier || '[]'); } catch { return []; } })();

// (Optional) parse service exclusion tags if present; not required for logic
const SELECTABLE_EXCLUSION_TAGS = Array.isArray(CONSTANTS.selectableValueServiceExclusionTags)
  ? CONSTANTS.selectableValueServiceExclusionTags
  : (() => { try { return JSON.parse(CONSTANTS.selectableValueServiceExclusionTags || '[]'); } catch { return []; } })();

// Robust RULES parsing (supports string, array, or { rules: [] })
let RULES = [];
if (CONSTANTS.rules) {
  if (typeof CONSTANTS.rules === 'string') {
    try {
      const parsed = JSON.parse(CONSTANTS.rules);
      RULES = Array.isArray(parsed) ? parsed : (parsed.rules || []);
    } catch {}
  } else if (Array.isArray(CONSTANTS.rules)) {
    RULES = CONSTANTS.rules;
  } else if (typeof CONSTANTS.rules === 'object' && Array.isArray(CONSTANTS.rules.rules)) {
    RULES = CONSTANTS.rules.rules;
  }
}

// Helpers
function getArticle(articles, id) {
  return (articles || []).find(a => String(a.id) === String(id));
}
function getCustomAttr(attrs, id) {
  return (attrs || []).find(a => String(a.attributeDefinitionId) === String(id));
}
function getExclusionTags(article) {
  const attr = getCustomAttr(article.customAttributes, ATTR_ID_EXCLUSION_TAGS);
  if (!attr || !Array.isArray(attr.selectedValues)) return [];
  const ids = attr.selectedValues.map(v => String(v.id)).filter(Boolean);
  const labels = attr.selectedValues.map(v => String(v.value || '')).filter(Boolean);
  return [...new Set([...ids, ...labels])];
}
function getDefaultCarrierSelectableId(article) {
  const attr = getCustomAttr(article.customAttributes, ATTR_ID_DEFAULT_CARRIER);
  return attr?.selectedValueId ? String(attr.selectedValueId) : null;
}
function getKleinpaketShare(article) {
  const attr = getCustomAttr(article.customAttributes, ATTR_ID_KLEINPAKET_SHARE);
  if (!attr || attr.numberValue === null || attr.numberValue === undefined) return 0;
  const share = parseFloat(attr.numberValue);
  return isNaN(share) ? 0 : share;
}
function resolveCarrierByName(name) {
  if (!name) return { id: null, name: null };
  const carrier = SHIPPING_CARRIERS.find(c => c.name === name);
  return carrier ? { id: String(carrier.id), name: carrier.name } : { id: null, name: name };
}
function resolveCarrierById(id) {
  const hit = SHIPPING_CARRIERS.find(c => String(c.id) === String(id));
  return hit ? { id: String(hit.id), name: hit.name } : { id: null, name: null };
}
function mapSelectableDefaultToCarrier(selectableId) {
  if (!selectableId) return { id: null, name: null };
  const entry = SELECTABLE_DEFAULT_CARRIER.find(sv => String(sv.id) === String(selectableId));
  const nameFromSelectable = entry?.value || null;
  return resolveCarrierByName(nameFromSelectable);
}

// Resolve nested fields safely
function resolvePath(obj, path) {
  return path.split('.').reduce((acc, key) => acc?.[key], obj);
}

// Evaluate a single condition with normalization
function evaluateCondition(cond, context) {
  const { field, operator, value } = cond;
  const fieldValue = resolvePath(context, field);

  switch (operator) {
    case '==':  return fieldValue == value;
    case '!=':  return fieldValue != value;
    case '<':   return Number(fieldValue) < Number(value);
    case '<=':  return Number(fieldValue) <= Number(value);
    case '>':   return Number(fieldValue) > Number(value);
    case '>=':  return Number(fieldValue) >= Number(value);
    case 'contains': {
      if (!Array.isArray(fieldValue)) return false;
      const needle = String(value);
      return fieldValue.map(String).includes(needle);
    }
    case 'notContains': {
      if (!Array.isArray(fieldValue)) return false;
      const needle = String(value);
      return !fieldValue.map(String).includes(needle);
    }
    case 'matches': {
      if (typeof fieldValue !== 'string') return false;
      let re;
      try {
        re = new RegExp(value, 'i');
      } catch (e) {
        return false;
      }
      return re.test(fieldValue.trim());
    }
    default: return false;
  }
}

// Evaluate all rules in priority order
function applyRules(order, referencedArticles) {
  let totalWeight = 0;
  let exclusionTags = [];
  let totalItemCount = 0;
  let totalKleinpaketShare = 0;

  (order.orderItems || []).forEach(oi => {
    const article = getArticle(referencedArticles, oi.articleId);
    if (!article || article.articleType !== 'STORABLE') return;

    const qty = parseInt(oi.quantity || 0, 10) || 0;

    const w = parseFloat(article.articleGrossWeight || 0);
    totalWeight += w * qty;

    const kleinpaketShare = getKleinpaketShare(article);
    totalKleinpaketShare += kleinpaketShare * qty;

    exclusionTags = exclusionTags.concat(getExclusionTags(article));
    totalItemCount += qty;
  });

  exclusionTags = [...new Set(exclusionTags.map(String))];

  const context = {
    order,
    deliveryAddress: order.deliveryAddress || {},
    totalWeightKg: totalWeight,
    exclusionTags,
    itemCount: totalItemCount,
    totalKleinpaketShare
  };

  const sorted = [...RULES].sort((a, b) => (a.priority ?? 9999) - (b.priority ?? 9999));

  for (const rule of sorted) {
    const conditions = rule.conditions || [];
    const match = conditions.every(c => evaluateCondition(c, context));
    if (match) {
      if (rule.carrierName) {
        return resolveCarrierByName(rule.carrierName);
      }
      if (rule.carrierNameFrom === 'defaultCarrier' && context.itemCount === 1) {
        const firstStorable = (order.orderItems || [])
          .map(oi => getArticle(referencedArticles, oi.articleId))
          .find(a => a && a.articleType === 'STORABLE');

        if (!firstStorable) return resolveCarrierByName('DHL Paket');

        const selectableId = getDefaultCarrierSelectableId(firstStorable);
        const mapped = mapSelectableDefaultToCarrier(selectableId);
        return mapped.id ? mapped : resolveCarrierByName('DHL Paket');
      }
    }
  }

  // Fallback: default carrier of first STORABLE article; if missing, use general default (DHL Paket)
  if (order.orderItems?.length) {
    const firstStorable = order.orderItems
      .map(oi => getArticle(referencedArticles, oi.articleId))
      .find(a => a && a.articleType === 'STORABLE');
    if (firstStorable) {
      const selectableId = getDefaultCarrierSelectableId(firstStorable);
      const mapped = mapSelectableDefaultToCarrier(selectableId);
      return mapped.id ? mapped : resolveCarrierByName('DHL Paket');
    }
  }
  return resolveCarrierByName('DHL Paket');
}

// Main
return $input.all().map(item => {
  const order = item.json.result || {};
  const referencedArticles = (item.json.referencedEntities || {}).article || [];

  const { id: carrierId } = applyRules(order, referencedArticles);
  order.defaultShippingCarrierId = carrierId || null;

  delete order.orderItems;
  item.json = order;
  return item;
});

const payload = $input.first().json;
const shipments = Array.isArray(payload.result) ? payload.result : [];
const refSalesOrders = payload.referencedEntities?.salesOrder || [];
const salesOrderById = Object.fromEntries(refSalesOrders.map(o => [String(o.id), o]));
const allowed = new Set($('Edit fields Constants').first().json.salesChannelsWithReturnLabel || []);
const kept = shipments.filter(s => {
  const so = s.mainSalesOrderId ? salesOrderById[String(s.mainSalesOrderId)] : null;
  return so && allowed.has(so.salesChannel);
});
return [{ json: { result: kept }, pairedItem: { item: 0 } }];

