const items = $input.all();
const salesOrders = $('Split Out salesOrders').all();
const constants = $('Edit fields Constants').first().json;

const [cutoffHours, cutoffMinutes] = constants.shippingCutoffTime.split(':').map(Number);

const addItemRules = Array.isArray(constants.addItemRules) ? constants.addItemRules : [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const salesOrder = salesOrders[i].json.result;

  const salesChannel = salesOrder.salesChannel;

  // Legacy postCardsMapping support (salesChannel-based article additions)
  const mapping = (constants.postCardsMapping || []).find(m => m.salesChannel === salesChannel);

  const whitelabelMapping = constants.salesChannelsWithWhitelabelAddresses?.find(
    m => m.salesChannel === salesChannel
  );

  let createdDate = salesOrder.createdDate;
  if (!createdDate || isNaN(createdDate)) {
    createdDate = Date.now();
  }

  const berlinTime = new Date(createdDate).toLocaleTimeString('de-DE', {
    timeZone: 'Europe/Berlin',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false
  });
  const parts = berlinTime.split(':');
  const hours = Number(parts[0]);
  const minutes = Number(parts[1]);
  const isBefore1530 = hours < cutoffHours || (hours === cutoffHours && minutes <= cutoffMinutes);

  let targetDate = new Date(createdDate);
  if (!isBefore1530) {
    targetDate = new Date(createdDate + 24 * 60 * 60 * 1000);
  }

  let berlinDateStr = targetDate.toLocaleDateString('en-CA', { timeZone: 'Europe/Berlin' });
  let [year, month, day] = berlinDateStr.split('-').map(Number);
  let dayOfWeek = new Date(year, month - 1, day).getDay();

  if (dayOfWeek === 6) {
    targetDate = new Date(targetDate.getTime() + 2 * 24 * 60 * 60 * 1000);
  } else if (dayOfWeek === 0) {
    targetDate = new Date(targetDate.getTime() + 1 * 24 * 60 * 60 * 1000);
  }

  berlinDateStr = targetDate.toLocaleDateString('en-CA', { timeZone: 'Europe/Berlin' });
  [year, month, day] = berlinDateStr.split('-').map(Number);
  const plannedShippingDate = Date.UTC(year, month - 1, day, 12, 0, 0, 0);

  const orderItems = salesOrder.orderItems.map(oi => ({ id: oi.id }));

  // Legacy postCardsMapping (salesChannel -> articleId)
  if (mapping) {
    orderItems.push({
      articleId: mapping.articleId,
      quantity: "1",
      unitPrice: 0
    });
  }

  // addItemRules: flexible article additions by salesChannel, triggerArticleId, or both
  // Each rule can have optional salesChannel and/or triggerArticleId conditions.
  // Always adds exactly 1 piece per matched rule per order.
  const orderArticleIds = new Set(
    (salesOrder.orderItems || []).map(oi => String(oi.articleId))
  );

  for (const rule of addItemRules) {
    const hasSalesChannelCondition = rule.salesChannel && String(rule.salesChannel).trim() !== '';
    const hasArticleCondition = rule.triggerArticleId && String(rule.triggerArticleId).trim() !== '';

    if (!hasSalesChannelCondition && !hasArticleCondition) continue;

    let match = true;
    if (hasSalesChannelCondition && salesChannel !== rule.salesChannel) match = false;
    if (hasArticleCondition && !orderArticleIds.has(String(rule.triggerArticleId))) match = false;

    if (match && rule.addArticleId) {
      orderItems.push({
        articleId: String(rule.addArticleId),
        quantity: String(rule.addQuantity || "1"),
        unitPrice: rule.addUnitPrice ?? 0
      });
    }
  }

  const weclappBody = {
    customAttributes: [
      {
        attributeDefinitionId: constants.attributeIdShippingCarrierChecked,
        booleanValue: true
      },
      {
        attributeDefinitionId: constants.attributeIdSalesChannel,
        stringValue: salesChannel
      }
    ],
    defaultShippingCarrierId: item.json.defaultShippingCarrierId,
    defaultShippingCarrierName: item.json.defaultShippingCarrierName,
    defaultShippingReturnCarrierId: constants.defaultShippingReturnCarrierId.id,
    orderNumberAtCustomer: salesOrder.orderNumber,
    plannedShippingDate,
    status: "ORDER_CONFIRMATION_PRINTED",
    orderItems
  };

  if (whitelabelMapping) {
    weclappBody.description = JSON.stringify({
      whiteLabelSenderAddress: whitelabelMapping.whiteLabelSenderAddress
    });
  }

  item.json.weclappBody = weclappBody;
}

return items;

const data = $input.item.json;
const orders = data.result || [];
const articles = data.referencedEntities?.article || [];
const attributeIdEinzelnVerpackt = $('Edit fields Constants').item.json.attributeIdEinzelnVerpackt;

const articleMap = new Map();
for (const article of articles) {
  const attrs = article.customAttributes || [];
  const evAttr = attrs.find(a => String(a.attributeDefinitionId) === String(attributeIdEinzelnVerpackt));
  articleMap.set(String(article.id), {
    id: article.id,
    articleNumber: article.articleNumber,
    articleType: article.articleType,
    einzelnVerpackt: evAttr?.booleanValue === true
  });
}

const enrichedOrders = orders.map(order => {
  const orderItems = order.orderItems || [];
  const hasEinzelnVerpackt = orderItems.some(item => {
    const articleInfo = articleMap.get(String(item.articleId));
    return articleInfo?.einzelnVerpackt === true;
  });

  const enrichedItems = orderItems.map(item => {
    const articleInfo = articleMap.get(String(item.articleId));
    return {
      ...item,
      einzelnVerpackt: articleInfo?.einzelnVerpackt || false,
      articleNumber: articleInfo?.articleNumber,
      articleType: articleInfo?.articleType || null
    };
  });

  return {
    ...order,
    orderItems: enrichedItems,
    hasEinzelnVerpackt
  };
});

return [{ json: { result: enrichedOrders } }];

const order = $('Split Out salesOrders2').item.json;
const constants = $('Edit fields Constants').first().json;

return {
  json: {
    order: order,
    constants: constants
  }
}

